# DE 1705.  Hannover Hbf - Seelze
#
let hs = path("d3.de.1705");

with detail = 4,
     railway = :first :double :cat:ac15 :pax
{
    with link = "point.de.Hannover-Leinhausen", railway = :station {
        track(:lor, hs[:hle - 0.5sw, :hle + 0.5sw] >> 2mo);
        marker(:right :de.hp,
            hs[:hle] >> 2.5mo >> 0.5mt,
            hs[:hle] >> 1.5mo << 0.5mt
        );
        station(:top, hs[:hle] >> 2.5mo >> 0.5mt >> 1sh + (0dt, -0.5dt),
            vbox(:center:base, " Hannover-", "Leinhausen"),
            hbox(:center:top,
                vbox(:right:top,
                    "1705: ",
                    span(:former, "1700: "),
                    span(:former, "1701: ")
                ),
                vbox(:sep:top,
                    hbox(:sep:base, "5,", anchor(), "465"),
                    hbox(:sep:base :former, "5,", anchor(), "44"),
                    hbox(:sep:base :former, "5,", anchor(), "43")
                )
            )
        );
    }

    with link = "line.de.1705" {
        track(:lor, hs[:hle + 0.49sw, :kur - 0.9dl] >> 2mo);
        track(:lor, hs[:kur - 1dl, :kur + 0.51seg] >> 2mo);
        track(:lor, hs[:kur + 0.5seg, :lea + 0.1dl] >> 2mo);
        with layer = -1 track(:lor, hs[:lea, :lea.yr - 2mo] >> 2mo);
        track(:lor, hs[:lea.yr - 2.01mo, :let.yl + 0.1dl] >> 2mo);
    }

    with link = "point.de.Letter", railway = :station {
        track(hs[:let.yl, :let + 0.5sw] >> 2mo);
        marker(:right :de.hp :casing,
            hs[:let] >> 2.5mo >> 0.5mt,
            hs[:let] >> 1.5mo << 0.5mt
        );
        station(:top, hs[:let] >> 2.5mo >> 0.5mt >> 1sh + (-0.5dt, -0.6dt),
            "Letter",
            hbox(:center:top,
                vbox(:right:top, "1705: ", span(:former, "1700: ")),
                vbox(:sep:top,
                    hbox(:sep:base, "7,", anchor(), "983"),
                    hbox(:sep:base :former, "8,", anchor(), "22")
                )
            )
        );
    }

    with link = "line.de.1705" {
        track(:lor, hs[:let + 0.49sw, :sem] >> 2mo);
        track(:lor, hs[:sem, :see - 549m] >> 2mo);
    }

    # point.de.Seelze  de.1700
}

